patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 6fe969358185..77119c4524ae 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -853,6 +853,7 @@ static Instruction *foldNoWrapAdd(BinaryOperator &Add,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   Value *Op0 = Add.getOperand(0), *Op1 = Add.getOperand(1);
   Type *Ty = Add.getType();
@@ -924,6 +925,23 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   if (match(Op0, m_Or(m_Value(), m_APInt(C2))) && *C2 == -*C)
     return BinaryOperator::CreateXor(Op0, ConstantInt::get(Add.getType(), *C2));

+  // add(umax(X, C), -C) -> usub.sat(X, C)
+  // umax(X, C) + (-C) = max(X, C) - C = X - C when X >= C, else 0
+  // This matches usub.sat semantics.
+  if (match(Op0, m_OneUse(m_Intrinsic<Intrinsic::umax>(m_Value(X), m_APInt(C2)))) &&
+      *C == -*C2) {
+    Function *F = Intrinsic::getOrInsertDeclaration(
+        Add.getModule(), Intrinsic::usub_sat, Ty);
+    return CallInst::Create(F, {X, ConstantInt::get(Ty, *C2)});
+  }
+  // Handle commutative case: add(umax(C, X), -C) -> usub.sat(X, C)
+  if (match(Op0, m_OneUse(m_Intrinsic<Intrinsic::umax>(m_APInt(C2), m_Value(X)))) &&
+      *C == -*C2) {
+    Function *F = Intrinsic::getOrInsertDeclaration(
+        Add.getModule(), Intrinsic::usub_sat, Ty);
+    return CallInst::Create(F, {X, ConstantInt::get(Ty, *C2)});
+  }
+
   if (C->isSignMask()) {
     // If wrapping is not allowed, then the addition must set the sign bit:
     // X + (signmask) --> X | signmask
@@ -1007,6 +1025,7 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   return nullptr;
 }

+
 // match variations of a^2 + 2*a*b + b^2
 //
 // to reuse the code between the FP and Int versions, the instruction OpCodes
